// app/metrics/page.tsx
import { Suspense } from 'react';

async function getMetrics() {
  const res = await fetch('http://127.0.0.1:5000/metrics/server', {
    next: { revalidate: 10 } // Revalidate every 10 seconds
  });
  if (!res.ok) throw new Error('Failed to fetch metrics');
  return res.json();
}

export default async function MetricsPage() {
  const metrics = await getMetrics();

  return (
    <div className="metrics-grid">
      <MetricCard 
        title="Uptime (30d)" 
        value={`${metrics.uptime.percentage_30d}%`}
        trend="up"
      />
      <MetricCard 
        title="API p95" 
        value={`${metrics.api_latency.p95_ms}ms`}
        trend={metrics.api_latency.p95_ms < 500 ? 'good' : 'warning'}
      />
      <MetricCard 
        title="5xx Rate" 
        value={`${metrics.error_rates.error_5xx_rate_percent}%`}
        trend={metrics.error_rates.error_5xx_rate_percent < 1 ? 'good' : 'bad'}
      />
      <MetricCard 
        title="Kafka Lag" 
        value={metrics.kafka.consumer_lag.total_lag}
        trend={metrics.kafka.consumer_lag.total_lag < 1000 ? 'good' : 'warning'}
      />
    </div>
  );
}
